def create_token(user_id, email):
    jti = str(uuid.uuid4())
    payload = {
        'user_id': user_id,
        'email': email,
        'jti': jti,
        'exp': datetime.utcnow() + timedelta(days=30)
    }
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256'), jti

def verify_token(token):
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
    except Exception:
        return None
    if payload.get('admin'):
        return payload
    jti = payload.get('jti')
    if not jti:
        print("[AUTH] Token rejected: missing jti", flush=True)
        return None
    try:
        conn = get_conn()
        try:
            row = conn.execute(
                'SELECT user_id, expires_at FROM user_sessions WHERE token=?',
                (jti,)
            ).fetchone()
        finally:
            conn.close()
    except Exception:
        return None
    if not row:
        print(f"[AUTH] Token rejected: jti not in sessions ({jti[:8]}...)", flush=True)
        return None
    exp = row['expires_at']
    if exp and exp < datetime.utcnow():
        return None
    return payload


class BaseHandler(tornado.web.RequestHandler):
    def set_default_headers(self):
        self.set_header("Access-Control-Allow-Origin", "*")
        self.set_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
        self.set_header("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
        self.set_header("Content-Type", "application/json")

    def options(self, *args):
        self.set_status(204)
        self.finish()

    def get_current_user(self):
        auth = self.request.headers.get('Authorization', '')
        if auth.startswith('Bearer '):
            token = auth[7:]
            payload = verify_token(token)
            if payload:
                return payload
        # Aceita token via query param para download direto de PDF
        token = self.get_argument('token', None)
        if token:
            payload = verify_token(token)
            if payload:
                return payload
        return None

    def require_auth(self):
        user = self.get_current_user()
        if not user:
            self.set_status(401)
            self.write({'error': 'NÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ£o autenticado'})
            self.finish()
            return None
        return user

    def json_body(self):
        try:
            return json.loads(self.request.body)
        except Exception:
            return {}

    def ok(self, data=None, status=200):
        self.set_status(status)
        self.set_header('Content-Type', 'application/json; charset=UTF-8')
        self.write(json.dumps(data or {'ok': True}, default=_jser))

    def err(self, msg, status=400):
        self.set_status(status)
        self.set_header('Content-Type', 'application/json; charset=UTF-8')
        self.write(json.dumps({'error': msg}, default=_jser))

    def row_to_dict(self, row):
        if row is None:
            return None
        return dict(row)

