class RegisterHandler(BaseHandler):
    def post(self):
        data = self.json_body()

        name = (data.get('name') or '').strip()
        email = (data.get('email') or '').strip().lower()
        pwd = data.get('password') or ''
        pwd_confirm = data.get('password_confirm') or ''
        terms = data.get('terms_accepted')

        if not name or len(name) < 3:
            return self.err('Nome deve ter pelo menos 3 caracteres')

        if not email:
            return self.err('E-mail \u00e9 obrigat\u00f3rio')
        if not valid_email(email):
            return self.err('Formato de e-mail inv\u00e1lido')

        ok_pwd, msg_pwd = valid_password(pwd)
        if not ok_pwd:
            return self.err(msg_pwd)

        if pwd != pwd_confirm:
            return self.err('As senhas n\u00e3o coincidem')

        if not terms:
            return self.err('\u00c9 necess\u00e1rio aceitar os termos de uso')

        company_name = (data.get('company_name') or '').strip() or None
        creci = (data.get('creci') or '').strip() or None
        phone = (data.get('phone') or '').strip() or None
        cpf = (data.get('cpf') or '').strip() or None

        conn = get_conn()
        try:
            existing = conn.execute('SELECT id FROM users WHERE email=?', (email,)).fetchone()
            if existing:
                return self.err('E-mail j\u00e1 cadastrado')

            user_id = str(uuid.uuid4())
            now = datetime.utcnow()

            conn.execute('''INSERT INTO users
                            (id, name, email, password_hash, company_name, creci, phone, cpf,
                             status, balance_cents, terms_accepted_at, created_at, updated_at)
                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'pending_verification', 0, ?, ?, ?)''',
                         (user_id, name, email, hash_password_v2(pwd),
                          company_name, creci, phone, cpf,
                          now, now, now))
            conn.commit()

            vtoken = generate_verification_token()
            expires_at = now + timedelta(hours=24)
            conn.execute('INSERT INTO email_verification_tokens (user_id, token, expires_at) VALUES (?, ?, ?)',
                         (user_id, vtoken, expires_at))
            conn.commit()

            try:
                enqueue_verification_email(conn, user_id, email, name, vtoken)
                conn.commit()
            except Exception as _e:
                print(f'[AUTH] enqueue_verification_email failed: {_e}', flush=True)

            token, jti = create_token(user_id, email)
            conn.execute('''INSERT INTO user_sessions
                            (user_id, token, expires_at, ip, user_agent)
                            VALUES (?, ?, ?, ?, ?)''',
                         (user_id, jti,
                          now + timedelta(days=30),
                          self.request.remote_ip,
                          self.request.headers.get('User-Agent', '')))
            conn.commit()

            print(f'[AUTH] Register OK: {email} ({user_id})', flush=True)
            self.ok({'token': token, 'user': {
                'id': user_id,
                'name': name,
                'email': email,
                'company_name': company_name,
                'creci': creci,
                'phone': phone,
                'plan': 'free',
                'status': 'pending_verification',
                'balance_cents': 0,
                'balance_formatted': format_balance_brl(0),
                'email_verified': False
            }}, 201)
        finally:
            conn.close()

class LoginHandler(BaseHandler):
    def post(self):
        data = self.json_body()
        email = (data.get('email') or '').strip().lower()
        pwd = data.get('password') or ''

        if not email or not pwd:
            return self.err('E-mail e senha s\u00e3o obrigat\u00f3rios')

        conn = get_conn()
        try:
            row = conn.execute('SELECT * FROM users WHERE email=? AND active=1', (email,)).fetchone()
            if not row:
                return self.err('E-mail ou senha inv\u00e1lidos', 401)

            user = self.row_to_dict(row)

            if user.get('status') == 'blocked':
                reason = user.get('blocked_reason') or 'Conta bloqueada'
                return self.err(f'Conta bloqueada: {reason}', 403)

            stored_hash = user.get('password_hash') or ''
            if not verify_password_v2(pwd, stored_hash):
                return self.err('E-mail ou senha inv\u00e1lidos', 401)

            if not stored_hash.startswith('$2b$') and not stored_hash.startswith('$2a$'):
                try:
                    new_hash = hash_password_v2(pwd)
                    conn.execute('UPDATE users SET password_hash=? WHERE id=?', (new_hash, user['id']))
                    conn.commit()
                    print(f'[AUTH] Lazy bcrypt migration: {email}', flush=True)
                except Exception as _e:
                    print(f'[AUTH] Lazy migration failed: {_e}', flush=True)

            conn.execute('UPDATE users SET last_login_at=? WHERE id=?',
                         (datetime.utcnow(), user['id']))
            conn.commit()

            token, jti = create_token(user['id'], email)
            conn.execute('''INSERT INTO user_sessions
                            (user_id, token, expires_at, ip, user_agent)
                            VALUES (?, ?, ?, ?, ?)''',
                         (user['id'], jti,
                          datetime.utcnow() + timedelta(days=30),
                          self.request.remote_ip,
                          self.request.headers.get('User-Agent', '')))
            conn.commit()

            print(f'[AUTH] Login OK: {email}', flush=True)

            balance_cents = user.get('balance_cents') or 0
            self.ok({'token': token, 'user': {
                'id': user['id'],
                'name': user.get('name'),
                'email': email,
                'company_name': user.get('company_name'),
                'creci': user.get('creci'),
                'phone': user.get('phone'),
                'plan': user.get('plan') or 'free',
                'status': user.get('status') or 'active',
                'balance_cents': balance_cents,
                'balance_formatted': format_balance_brl(balance_cents),
                'email_verified': bool(user.get('email_verified_at'))
            }})
        finally:
            conn.close()

class MeHandler(BaseHandler):
    def get(self):
        user = self.require_auth()
        if not user:
            return
        conn = get_conn()
        try:
            user_id = user['user_id']
            row = conn.execute('SELECT * FROM users WHERE id=?', (user_id,)).fetchone()
            if not row:
                return self.err('Usu\u00e1rio n\u00e3o encontrado', 404)
            u = self.row_to_dict(row)
            for k in ('password_hash', 'google_id'):
                u.pop(k, None)
            balance_cents = u.get('balance_cents') or 0
            u['balance_cents'] = balance_cents
            u['balance_formatted'] = format_balance_brl(balance_cents)
            u['email_verified'] = bool(u.get('email_verified_at'))

            # Contadores de fotos do mes atual (agregado de balance_transactions)
            try:
                foto_rows = conn.execute(
                    "SELECT analysis_type, "
                    "COALESCE(SUM(photos_count), 0) AS total "
                    "FROM balance_transactions "
                    "WHERE user_id = ? "
                    "  AND type = 'analysis_debit' "
                    "  AND created_at >= date_trunc('month', NOW()) "
                    "GROUP BY analysis_type",
                    (user_id,)
                ).fetchall()
                fotos_map = {}
                for r_ in foto_rows:
                    tipo = r_.get('analysis_type') if hasattr(r_, 'get') else r_[0]
                    total = r_.get('total') if hasattr(r_, 'get') else r_[1]
                    try:
                        fotos_map[tipo] = int(total or 0)
                    except Exception:
                        fotos_map[tipo] = 0
                u['fotos_usadas_conv_mes'] = fotos_map.get('convencional', 0)
                u['fotos_usadas_prem_mes'] = fotos_map.get('premium', 0)
            except Exception as _e:
                # Em caso de falha, devolve zeros para nao quebrar o /me
                print(f'[ME] Erro ao agregar fotos do mes: {_e}', flush=True)
                u['fotos_usadas_conv_mes'] = 0
                u['fotos_usadas_prem_mes'] = 0

            self.ok(u)
        finally:
            conn.close()


class LogoutHandler(BaseHandler):
    def post(self):
        payload = self.require_auth()
        if not payload:
            return

        jti = payload.get('jti')
        if not jti:
            return self.ok({'ok': True, 'message': 'Logout realizado'})

        conn = get_conn()
        try:
            conn.execute(
                'DELETE FROM user_sessions WHERE token=?',
                (jti,)
            )
            conn.commit()

            user_id = payload.get('user_id', '')[:8]
            print(f'[AUTH] Logout OK: user_id={user_id}... jti={jti[:8]}...', flush=True)

            self.ok({'ok': True, 'message': 'Logout realizado'})
        except Exception as e:
            conn.rollback()
            print(f'[AUTH] Logout ERROR: {e}', flush=True)
            return self.err(f'Erro ao fazer logout: {str(e)}', 500)
        finally:
            conn.close()


