# -- PASSWORD RESET ----------------------------------------------------------

class PasswordResetRequestHandler(BaseHandler):
    """POST /api/auth/forgot-password  { email }"""
    def post(self):
        data = self.json_body()
        email = (data.get('email') or '').strip().lower()
        if not email:
            return self.err('E-mail obrigatorio')
        conn = get_conn()
        try:
            user = conn.execute('SELECT id, email FROM users WHERE email=? AND active=1',
                                (email,)).fetchone()
            if not user:
                return self.ok({'ok': True})
            user = dict(user)
            token = secrets.token_urlsafe(48)
            expires_at = datetime.utcnow() + timedelta(minutes=30)
            conn.execute(
                'INSERT INTO password_reset_tokens (token, user_id, email, expires_at) VALUES (?,?,?,?)',
                (token, user['id'], user['email'], expires_at.isoformat())
            )
            conn.commit()
            base_url = self.request.full_url().split('/api/')[0]
            reset_link = base_url + '/?reset_token=' + token
            subject = 'Redefinir senha - izyLAUDO'
            body_html = (
                '<html><body style="font-family:Arial,sans-serif;'
                'max-width:600px;margin:0 auto;padding:20px">'
                '<h2 style="color:#1e3a5f">Redefinir senha</h2>'
                '<p>Ola! Recebemos uma solicitacao para redefinir '
                'a senha da sua conta izyLAUDO.</p>'
                '<p>Clique no botao abaixo para criar uma nova senha:</p>'
                '<p style="text-align:center;margin:30px 0">'
                f'<a href="{reset_link}" style="background:#2d7dd2;'
                'color:#fff;padding:14px 28px;border-radius:8px;'
                'text-decoration:none;font-weight:bold">'
                'Redefinir Senha</a></p>'
                '<p style="color:#666;font-size:13px">'
                f'Ou copie: {reset_link}</p>'
                '<p style="color:#666;font-size:13px">'
                'Este link expira em 30 minutos.</p>'
                '<p style="color:#999;font-size:12px">'
                'Se voce nao solicitou, ignore este email.</p>'
                '</body></html>'
            )
            body_text = (
                'Redefinir senha - izyLAUDO\n\n'
                'Clique no link para criar uma nova senha:\n'
                f'{reset_link}\n\n'
                'O link expira em 30 minutos.\n\n'
                'Se voce nao solicitou, ignore este email.'
            )
            conn.execute(
                'INSERT INTO email_queue '
                '(user_id, to_email, template, subject, body_html, body_text, status) '
                "VALUES (?, ?, 'password_reset', ?, ?, ?, 'pending')",
                (user['id'], user['email'], subject, body_html, body_text)
            )
            conn.commit()
            self.ok({'ok': True})
        finally:
            conn.close()


class PasswordResetVerifyHandler(BaseHandler):
    """GET /api/auth/verify-reset-token?token=XXX"""
    def get(self):
        token = self.get_argument('token', '')
        if not token:
            return self.err('Token obrigatorio', 400)
        conn = get_conn()
        try:
            row = conn.execute(
                'SELECT * FROM password_reset_tokens WHERE token=?', (token,)
            ).fetchone()
            if not row:
                return self.err('Token invalido', 400)
            row = dict(row)
            if row['used']:
                return self.err('Token ja utilizado', 400)
            expires_str = str(row['expires_at']).split('+')[0].split('.')[0]
            expires_at = datetime.strptime(expires_str, '%Y-%m-%dT%H:%M:%S') if 'T' in expires_str else datetime.strptime(expires_str, '%Y-%m-%d %H:%M:%S')
            if datetime.utcnow() > expires_at:
                return self.err('Token expirado', 400)
            self.ok({'ok': True, 'email': row['email']})
        finally:
            conn.close()


class PasswordResetConfirmHandler(BaseHandler):
    """POST /api/auth/reset-password  { token, new_password }"""
    def post(self):
        data = self.json_body()
        token = (data.get('token') or '').strip()
        new_password = data.get('new_password') or ''
        if not token:
            return self.err('Token obrigatorio')
        ok_pwd, msg_err = valid_password(new_password)
        if not ok_pwd:
            return self.err(msg_err)
        conn = get_conn()
        try:
            row = conn.execute(
                'SELECT * FROM password_reset_tokens WHERE token=?', (token,)
            ).fetchone()
            if not row:
                return self.err('Token invalido')
            row = dict(row)
            if row['used']:
                return self.err('Token ja utilizado')
            expires_str = str(row['expires_at']).split('+')[0].split('.')[0]
            expires_at = datetime.strptime(expires_str, '%Y-%m-%dT%H:%M:%S') if 'T' in expires_str else datetime.strptime(expires_str, '%Y-%m-%d %H:%M:%S')
            if datetime.utcnow() > expires_at:
                return self.err('Token expirado')
            conn.execute(
                'UPDATE users SET password_hash=? WHERE id=?',
                (hash_password_v2(new_password), row['user_id'])
            )
            conn.execute(
                'UPDATE password_reset_tokens SET used=1 WHERE token=?', (token,)
            )
            conn.execute(
                'DELETE FROM user_sessions WHERE user_id=?',
                (row['user_id'],)
            )
            print(f"[AUTH] Sessions invalidated (pwd reset): user_id={row['user_id'][:8]}...", flush=True)
            conn.commit()
            self.ok({'ok': True})
        finally:
            conn.close()


class EmailVerifyHandler(BaseHandler):
    """
    GET /verify-email?token=<token>
    Valida o token de verificacao de email. Em sucesso:
      - marca users.email_verified_at = NOW(), status='active'
      - credita bonus de boas-vindas (settings.welcome_bonus_cents, fallback 500)
      - insere linha em balance_transactions (type='bonus')
      - marca email_verification_tokens.used_at = NOW()
    Redireciona para SPA com ?verified=true&bonus=... em sucesso,
    ou ?verify_error=<motivo> em falha.
    """

    def _redirect_error(self, reason):
        self.redirect(f'/?verify_error={reason}')

    def get(self):
        vtoken = (self.get_argument('token', '') or '').strip()
        if not vtoken:
            return self._redirect_error('missing')

        conn = get_conn()
        try:
            row = conn.execute(
                'SELECT id, user_id, expires_at, used_at '
                'FROM email_verification_tokens WHERE token=?',
                (vtoken,)
            ).fetchone()
            if not row:
                return self._redirect_error('invalid')

            token_id = row['id']
            user_id = row['user_id']
            expires_at = row['expires_at']
            used_at = row['used_at']

            if used_at is not None:
                print(f'[AUTH] verify_email_already_used user_id={user_id} '
                      f'token_id={token_id}', flush=True)
                return self._redirect_error('already_used')

            if expires_at and expires_at < datetime.utcnow():
                print(f'[AUTH] verify_email_expired user_id={user_id} '
                      f'token_id={token_id}', flush=True)
                return self._redirect_error('expired')

            bonus_cents = 500
            try:
                srow = conn.execute(
                    "SELECT value FROM settings WHERE key='welcome_bonus_cents'"
                ).fetchone()
                if srow and srow['value'] is not None:
                    bonus_cents = int(srow['value'])
            except Exception as _e:
                print(f'[AUTH] welcome_bonus_cents read failed, fallback 500: {_e}',
                      flush=True)

            conn.execute(
                "UPDATE users SET email_verified_at=NOW(), status='active', "
                "balance_cents=balance_cents+?, updated_at=NOW() WHERE id=?",
                (bonus_cents, user_id)
            )
            u = conn.execute(
                'SELECT balance_cents FROM users WHERE id=?',
                (user_id,)
            ).fetchone()
            balance_after = int(u['balance_cents']) if u else bonus_cents

            conn.execute(
                'INSERT INTO balance_transactions '
                '(user_id, type, amount_cents, balance_after_cents, description) '
                'VALUES (?, ?, ?, ?, ?)',
                (user_id, 'bonus', bonus_cents, balance_after, 'Bonus de boas-vindas')
            )
            conn.execute(
                'UPDATE email_verification_tokens SET used_at=NOW() WHERE id=?',
                (token_id,)
            )
            conn.commit()

            print(f'[AUTH] email_verified user_id={user_id} '
                  f'bonus_cents={bonus_cents} new_balance={balance_after}',
                  flush=True)

            bonus_q = tornado.escape.url_escape(format_balance_brl(bonus_cents))
            self.redirect(f'/?verified=true&bonus={bonus_q}')
        except Exception as e:
            try:
                conn.rollback()
            except Exception:
                pass
            print(f'[AUTH] email_verify_error: {e}', flush=True)
            self._redirect_error('server_error')
        finally:
            try:
                conn.close()
            except Exception:
                pass


