# ============================================================================
# IA prices scraping (task #72) — atualiza tabela ia_prices 1x/dia
# ============================================================================

def scrape_ia_prices():
    """Scraping diario dos precos oficiais da Anthropic e Google Gemini.

    Atualiza a tabela ia_prices. Em caso de falha, apenas marca scraping_ok
    como FALSE e mantem os valores anteriores (nao quebra cobranca).
    """
    import re as _re
    import requests as _req

    results = []

    # === ANTHROPIC ===
    try:
        _r = _req.get(
            'https://platform.claude.com/docs/en/about-claude/pricing',
            timeout=15, headers={'User-Agent': 'Mozilla/5.0'},
        )
        _txt = _r.text or ''
        _s_in = _re.search(
            r'[Ss]onnet.*?\$(\d+\.?\d*)\s*(?:per million|/1M|/MTok)',
            _txt, _re.DOTALL,
        )
        _s_out = _re.search(
            r'[Ss]onnet.*?\$\d+\.?\d*.*?\$(\d+\.?\d*)\s*(?:per million|/1M|output)',
            _txt, _re.DOTALL,
        )
        if _s_in and _s_out:
            _in_usd = float(_s_in.group(1)) / 1_000_000
            _out_usd = float(_s_out.group(1)) / 1_000_000
            results.append({
                'provider': 'claude', 'model': 'claude-sonnet-4-6',
                'input_price_usd': _in_usd, 'output_price_usd': _out_usd,
                'scraping_ok': True,
            })
            print('[SCRAPE] Anthropic Sonnet input=$%.8f output=$%.8f'
                  % (_in_usd, _out_usd), flush=True)
        else:
            print('[SCRAPE] Anthropic: precos nao encontrados no HTML - mantendo valores', flush=True)
            results.append({'provider': 'claude', 'model': 'claude-sonnet-4-6', 'scraping_ok': False})
    except Exception as _e:
        print('[SCRAPE] Anthropic error: ' + str(_e), flush=True)
        results.append({'provider': 'claude', 'model': 'claude-sonnet-4-6', 'scraping_ok': False})

    # === GOOGLE GEMINI ===
    try:
        _r = _req.get(
            'https://ai.google.dev/gemini-api/docs/pricing',
            timeout=15, headers={'User-Agent': 'Mozilla/5.0'},
        )
        _txt = _r.text or ''
        _f_in = _re.search(
            r'2\.5\s*[Ff]lash.*?\$(\d+\.?\d*)\s*(?:per million|/1M)',
            _txt, _re.DOTALL,
        )
        _f_out = _re.search(
            r'2\.5\s*[Ff]lash.*?\$\d+\.?\d*.*?\$(\d+\.?\d*)\s*(?:per million|/1M|output)',
            _txt, _re.DOTALL,
        )
        if _f_in and _f_out:
            _in_usd = float(_f_in.group(1)) / 1_000_000
            _out_usd = float(_f_out.group(1)) / 1_000_000
            results.append({
                'provider': 'gemini', 'model': 'gemini-2.5-flash',
                'input_price_usd': _in_usd, 'output_price_usd': _out_usd,
                'scraping_ok': True,
            })
            print('[SCRAPE] Gemini Flash input=$%.8f output=$%.8f'
                  % (_in_usd, _out_usd), flush=True)
        else:
            print('[SCRAPE] Gemini: precos nao encontrados - mantendo valores', flush=True)
            results.append({'provider': 'gemini', 'model': 'gemini-2.5-flash', 'scraping_ok': False})
    except Exception as _e:
        print('[SCRAPE] Gemini error: ' + str(_e), flush=True)
        results.append({'provider': 'gemini', 'model': 'gemini-2.5-flash', 'scraping_ok': False})

    # Persistir no banco
    try:
        conn = get_conn()
        try:
            for r in results:
                if r.get('scraping_ok') and r.get('input_price_usd') is not None:
                    conn.execute(
                        'INSERT INTO ia_prices '
                        '(provider, model, input_price_usd, output_price_usd, updated_at, scraping_ok) '
                        'VALUES (?, ?, ?, ?, NOW(), TRUE) '
                        'ON CONFLICT (provider, model) DO UPDATE SET '
                        '  input_price_usd = EXCLUDED.input_price_usd, '
                        '  output_price_usd = EXCLUDED.output_price_usd, '
                        '  updated_at = NOW(), scraping_ok = TRUE',
                        (r['provider'], r['model'],
                         r['input_price_usd'], r['output_price_usd']),
                    )
                else:
                    conn.execute(
                        'UPDATE ia_prices SET scraping_ok = FALSE, updated_at = NOW() '
                        'WHERE provider = ? AND model = ?',
                        (r['provider'], r['model']),
                    )
            conn.commit()
            print('[SCRAPE] Precos salvos no banco', flush=True)
        finally:
            conn.close()
    except Exception as _e:
        print('[SCRAPE] DB persist error: ' + str(_e), flush=True)

    return results


def _run_daily_scraping():
    """Thread daemon: roda o scraping 1x por dia apos aguardar boot."""
    import time as _t
    _t.sleep(30)  # aguardar app inicializar
    while True:
        try:
            print('[SCRAPE] Iniciando scraping diario de precos...', flush=True)
            scrape_ia_prices()
        except Exception as _e:
            print('[SCRAPE] Scheduler error: ' + str(_e), flush=True)
        _t.sleep(86400)  # 24h


class AdminIAPricesHandler(AdminHandler):
    def get(self):
        if not self.require_admin():
            return
        conn = get_conn()
        try:
            rows = conn.execute(
                'SELECT provider, model, input_price_usd, output_price_usd, '
                '       updated_at, source_url, scraping_ok '
                'FROM ia_prices ORDER BY provider'
            ).fetchall()
            prices = []
            for r in rows:
                d = dict(r)
                # Serializar numeric/timestamp para JSON
                if d.get('updated_at') is not None:
                    d['updated_at'] = str(d['updated_at'])
                if d.get('input_price_usd') is not None:
                    d['input_price_usd'] = float(d['input_price_usd'])
                if d.get('output_price_usd') is not None:
                    d['output_price_usd'] = float(d['output_price_usd'])
                prices.append(d)

            _rate_row = conn.execute(
                "SELECT value FROM settings WHERE key = 'usd_brl_rate'"
            ).fetchone()
            try:
                usd_brl = float(_rate_row['value']) if (_rate_row and _rate_row.get('value')) else 5.70
            except Exception:
                usd_brl = 5.70

            self.ok({'prices': prices, 'usd_brl_rate': usd_brl})
        finally:
            conn.close()

    def post(self):
        if not self.require_admin():
            return
        try:
            data = json.loads(self.request.body or b'{}')
        except Exception:
            data = {}

        if data.get('action') == 'scrape_now':
            try:
                results = scrape_ia_prices()
                self.ok({'ok': True, 'results': results})
            except Exception as _e:
                self.set_status(500)
                self.ok({'ok': False, 'error': str(_e)})
            return

        if 'usd_brl_rate' in data:
            try:
                val = str(float(data['usd_brl_rate']))
            except Exception:
                self.set_status(400)
                self.ok({'ok': False, 'error': 'usd_brl_rate invalido'})
                return
            conn = get_conn()
            try:
                conn.execute(
                    "INSERT INTO settings (key, value, value_type, category, updated_at) "
                    "VALUES ('usd_brl_rate', ?, 'number', 'exchange', NOW()) "
                    "ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW()",
                    (val,),
                )
                conn.commit()
                self.ok({'ok': True, 'usd_brl_rate': float(val)})
            finally:
                conn.close()
            return

        self.set_status(400)
        self.ok({'ok': False, 'error': 'Acao invalida'})


# ============================================================================
# Admin password management (task #74)
# ----------------------------------------------------------------------------
# Senha do admin vive em settings.admin_password. Dois endpoints:
#  - POST /api/admin/change-password (autenticado): admin altera propria senha
#  - POST /api/admin/forgot-password (publico): gera nova senha aleatoria e
#    envia por email para ADMIN_EMAIL (financeiro@izylaudo.com.br)
# ============================================================================

class AdminChangePasswordHandler(AdminHandler):
    def post(self):
        if not self.require_admin():
            return
        try:
            data = json.loads(self.request.body or b'{}')
        except Exception:
            data = {}
        nova = str(data.get('nova_senha') or '').strip()
        conf = str(data.get('confirmar') or '').strip()

        if not nova or len(nova) < 8:
            self.set_status(400)
            self.ok({'ok': False, 'error': 'Senha deve ter no minimo 8 caracteres'})
            return
        if nova != conf:
            self.set_status(400)
            self.ok({'ok': False, 'error': 'Senhas nao conferem'})
            return

        conn = get_conn()
        try:
            conn.execute(
                "INSERT INTO settings (key, value, value_type, category, updated_at) "
                "VALUES ('admin_password', ?, 'string', 'auth', NOW()) "
                "ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW()",
                (nova,),
            )
            conn.commit()
        finally:
            conn.close()

        # Notifica por email (best-effort, nao bloqueia resposta)
        _html = (
            '<div style="font-family:Arial,sans-serif;max-width:480px;margin:0 auto;">'
            '<div style="background:#1e3a5f;padding:24px;border-radius:8px 8px 0 0;">'
            '<h2 style="color:#fff;margin:0;">izyLAUDO &mdash; Senha alterada</h2>'
            '</div>'
            '<div style="background:#f8fafc;padding:24px;border-radius:0 0 8px 8px;">'
            '<p style="color:#1e293b;">A senha do painel administrativo foi alterada com sucesso.</p>'
            '<div style="background:#fff;border:1px solid #e2e8f0;border-radius:8px;padding:16px;margin:16px 0;">'
            '<p style="margin:0;color:#64748b;font-size:13px;">Nova senha:</p>'
            '<p style="margin:4px 0 0;font-size:18px;font-weight:600;color:#1e3a5f;letter-spacing:1px;">'
            + nova.replace('<', '&lt;').replace('>', '&gt;')
            + '</p></div>'
            '<p style="color:#94a3b8;font-size:12px;">Se voce nao realizou esta alteracao, '
            'entre em contato imediatamente.</p>'
            '</div></div>'
        )
        try:
            send_email(ADMIN_EMAIL, 'izyLAUDO - Senha do admin alterada', _html)
        except Exception as _e:
            print('[EMAIL] change_password email_error: ' + str(_e), flush=True)

        self.ok({'ok': True})


class AdminForgotPasswordHandler(tornado.web.RequestHandler):
    """Publico: gera nova senha aleatoria e envia para ADMIN_EMAIL."""
    def post(self):
        import secrets as _secrets
        import string as _string
        alphabet = _string.ascii_letters + _string.digits + '!@#$'
        nova = ''.join(_secrets.choice(alphabet) for _ in range(12))

        conn = get_conn()
