class AnalyzePhotoHandler(BaseHandler):
    def post(self):
        try:
            user = self.require_auth()
            if not user:
                return

            data = tornado.escape.json_decode(self.request.body)
            image_b64 = data.get("image", "")
            room_name = data.get("ambiente", "Ambiente")
            modo = data.get("modo", "completo")
            mime_type = data.get("mime_type", "image/jpeg")
            tipo_analise = data.get("tipo_analise", "convencional")
            if tipo_analise not in ["convencional", "premium"]:
                tipo_analise = "convencional"

            if not image_b64:
                self.set_status(400)
                self.write({"error": "Imagem nao enviada"})
                return

            # === DEBITO AUTOMATICO ANTES DE CHAMAR A IA ===
            user_id = user['user_id']
            if tipo_analise == 'premium':
                price_key = 'price_per_photo_premium_cents'
                default_price = 90
            else:
                price_key = 'price_per_photo_convencional_cents'
                default_price = 50

            conn = get_conn()
            new_balance = None
            price_cents = default_price
            try:
                srow = conn.execute(
                    "SELECT value FROM settings WHERE key=?",
                    (price_key,)
                ).fetchone()
                if srow and srow.get('value') is not None:
                    try:
                        price_cents = int(srow['value'])
                    except Exception:
                        price_cents = default_price

                urow = conn.execute(
                    "SELECT balance_cents FROM users WHERE id=?",
                    (user_id,)
                ).fetchone()
                balance_cents = int(urow['balance_cents']) if urow and urow.get('balance_cents') is not None else 0

                if balance_cents < price_cents:
                    self.set_status(402)
                    self.write({
                        'ok': False,
                        'error': 'Saldo insuficiente. Adicione creditos para continuar.',
                        'code': 'insufficient_balance',
                        'balance_cents': balance_cents,
                        'price_cents': price_cents,
                    })
                    conn.close()
                    return

                new_balance = balance_cents - price_cents
                upd = conn.execute(
                    "UPDATE users SET balance_cents=?, updated_at=NOW() "
                    "WHERE id=? AND balance_cents>=?",
                    (new_balance, user_id, price_cents)
                )
                if upd.rowcount == 0:
                    # Race condition: saldo mudou entre SELECT e UPDATE
                    self.set_status(402)
                    self.write({
                        'ok': False,
                        'error': 'Saldo insuficiente. Adicione creditos para continuar.',
                        'code': 'insufficient_balance',
                    })
                    conn.close()
                    return

                descricao = ('Analise IA Premium - 1 foto'
                             if tipo_analise == 'premium'
                             else 'Analise IA Convencional - 1 foto')
                _insp_ref = (data.get('inspection_id')
                             or data.get('inspectionId') or None)
                conn.execute(
                    "INSERT INTO balance_transactions "
                    "(user_id, type, amount_cents, balance_after_cents, "
                    " description, status, analysis_type, photos_count, "
                    " inspection_id) "
                    "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    (user_id, 'analysis_debit', -price_cents, new_balance,
                     descricao, 'completed', tipo_analise, 1,
                     _insp_ref)
                )
                conn.commit()
                print(f"[BILLING] debit user={user_id} tipo={tipo_analise} "
                      f"cents={price_cents} new_balance={new_balance}",
                      flush=True)
            except Exception as _e:
                try:
                    conn.rollback()
                except Exception:
                    pass
                print(f"[BILLING] ERROR user={user_id} tipo={tipo_analise}: "
                      f"{_e}", flush=True)
                self.set_status(500)
                self.write({
                    'ok': False,
                    'error': 'Falha ao debitar saldo. Tente novamente.',
                    'code': 'billing_error',
                })
                try:
                    conn.close()
                except Exception:
                    pass
                return
            finally:
                try:
                    conn.close()
                except Exception:
                    pass
            # === FIM DEBITO AUTOMATICO ===

            # Remove data URL prefix if present
            if "," in image_b64:
                image_b64 = image_b64.split(",", 1)[1]

            result = analyze_image(image_b64, room_name, modo, mime_type, tipo_analise=tipo_analise)
            if isinstance(result, dict):
                result['balance_after_cents'] = new_balance
                result['debited_cents'] = price_cents
            self.write(result)

        except Exception as e:
            self.set_status(500)
            self.write({"error": str(e)})


class AnalisarBatchHandler(BaseHandler):
    def post(self):
        try:
            user = self.require_auth()
            if not user:
                return

            data = tornado.escape.json_decode(self.request.body)
            imagens = data.get("imagens", [])
            ambiente = data.get("ambiente", "Ambiente")

            if not imagens:
                self.set_status(400)
                self.write({"error": "Nenhuma imagem enviada", "success": False})
                return

            tipo_vistoria = data.get("tipo_vistoria", "entrada")
            tipo_analise = data.get("tipo_analise", "convencional")
            if tipo_analise not in ["convencional", "premium"]:
                tipo_analise = "convencional"

            qtd_fotos = len(imagens)

            # === DEBITO EM LOTE ANTES DE CHAMAR A IA ===
            user_id = user['user_id']
            if tipo_analise == 'premium':
                price_key = 'price_per_photo_premium_cents'
                default_price = 90
            else:
                price_key = 'price_per_photo_convencional_cents'
                default_price = 50

            conn = get_conn()
            new_balance = None
            total_cents = 0
            price_per_foto = default_price
            tx_id = None  # id da transacao analysis_debit (para update de custo IA)
            try:
                srow = conn.execute(
                    "SELECT value FROM settings WHERE key=?",
                    (price_key,)
                ).fetchone()
                if srow and srow.get('value') is not None:
                    try:
                        price_per_foto = int(srow['value'])
                    except Exception:
                        price_per_foto = default_price
                total_cents = price_per_foto * qtd_fotos

                urow = conn.execute(
                    "SELECT balance_cents FROM users WHERE id=?",
                    (user_id,)
                ).fetchone()
                balance_cents = int(urow['balance_cents']) if urow and urow.get('balance_cents') is not None else 0

                if balance_cents < total_cents:
                    self.set_status(402)
                    self.write({
                        'ok': False,
                        'error': 'Saldo insuficiente para analisar ' + str(qtd_fotos) + ' foto(s). Adicione creditos.',
                        'code': 'insufficient_balance',
                        'balance_cents': balance_cents,
                        'price_cents': total_cents,
                        'photos_count': qtd_fotos,
                    })
                    conn.close()
                    return

                new_balance = balance_cents - total_cents
                upd = conn.execute(
                    "UPDATE users SET balance_cents=?, updated_at=NOW() "
                    "WHERE id=? AND balance_cents>=?",
                    (new_balance, user_id, total_cents)
                )
                if upd.rowcount == 0:
                    self.set_status(402)
                    self.write({
                        'ok': False,
                        'error': 'Saldo insuficiente.',
                        'code': 'insufficient_balance',
                    })
                    conn.close()
                    return

                descricao = (
                    'Analise IA Premium - ' + str(qtd_fotos) + ' foto(s)'
                    if tipo_analise == 'premium'
                    else 'Analise IA Convencional - ' + str(qtd_fotos) + ' foto(s)'
                )
                _insp_ref = (data.get('inspection_id')
                             or data.get('inspectionId') or None)
                _tx_row = conn.execute(
                    "INSERT INTO balance_transactions "
                    "(user_id, type, amount_cents, balance_after_cents, "
                    " description, status, analysis_type, photos_count, "
                    " inspection_id) "
                    "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?) RETURNING id",
                    (user_id, 'analysis_debit', -total_cents, new_balance,
                     descricao, 'completed', tipo_analise, qtd_fotos,
                     _insp_ref)
                ).fetchone()
                tx_id = _tx_row['id'] if _tx_row else None
                conn.commit()
                print(f"[BILLING] batch_debit user={user_id} tipo={tipo_analise} "
                      f"qtd={qtd_fotos} total_cents={total_cents} "
                      f"new_balance={new_balance}", flush=True)
            except Exception as _e:
                try:
                    conn.rollback()
                except Exception:
                    pass
                print(f"[BILLING] ERROR batch user={user_id} tipo={tipo_analise} "
                      f"qtd={qtd_fotos}: {_e}", flush=True)
                self.set_status(500)
                self.write({
                    'ok': False,
                    'error': 'Falha ao debitar saldo. Tente novamente.',
                    'code': 'billing_error',
                })
                try:
                    conn.close()
                except Exception:
                    pass
                return
            finally:
                try:
                    conn.close()
                except Exception:
                    pass
            # === FIM DEBITO EM LOTE ===

            # Chama IA e reembolsa automaticamente se falhar apos retries.
            ia_err = None
            resultado = None
            try:
                resultado = analyze_batch(imagens, ambiente, tipo_vistoria,
                                          tipo_analise=tipo_analise)
            except Exception as _ia_e:
                ia_err = _ia_e
                print('[BILLING] ia_batch_error user=' + user_id
                      + ' total_cents=' + str(total_cents)
                      + ' reason=' + str(_ia_e)[:200], flush=True)

            # Detecta falha silenciosa (success=False ou resumo vazio)
            if ia_err is None and isinstance(resultado, dict):
                _has_resumo = bool((resultado.get('resumo') or '').strip())
                _success_flag = resultado.get('success', True)
                if (_success_flag is False) or (not _has_resumo):
                    ia_err = Exception('ia_empty_response')
                    print('[BILLING] ia_silent_fail user=' + user_id
                          + ' total_cents=' + str(total_cents)
                          + ' has_resumo=' + str(_has_resumo)
                          + ' success=' + str(_success_flag), flush=True)

            if ia_err is not None:
                # === FALLBACK GEMINI ===
                # Antes de reembolsar, tenta o Google Gemini 1.5 Flash.
                # Usuario nao percebe diferenca se o fallback funcionar.
                print('[AI] Claude falhou: ' + str(ia_err)[:120]
                      + ' - tentando Gemini fallback', flush=True)
                try:
                    _gem = analyze_with_gemini(
                        images=imagens,
                        ambiente=ambiente,
                        tipo_vistoria=tipo_vistoria,
                        tipo_analise=tipo_analise,
                    )
                    if (_gem and _gem.get('success')
                            and (_gem.get('resumo') or '').strip()):
                        print('[GEMINI] OK fallback user=' + user_id
                              + ' ambiente=' + str(ambiente)
                              + ' len=' + str(len(_gem['resumo'])),
                              flush=True)
                        # Calcular e gravar custo IA (task #71) — Gemini path
                        try:
                            _gem_in = int(_gem.get('input_tokens') or 0)
                            _gem_out = int(_gem.get('output_tokens') or 0)
                            _gem_model = _gem.get('model') or 'gemini-2.5-flash'
                            if tx_id and (_gem_in or _gem_out):
                                _cost_conn = get_conn()
                                try:
                                    _custo = calcular_custo_ia('gemini', _gem_model, _gem_in, _gem_out, _cost_conn)
                                    _cost_conn.execute(
                                        "UPDATE balance_transactions SET "
                                        "  ia_input_tokens=?, ia_output_tokens=?, "
                                        "  ia_custo_usd=?, ia_custo_brl=?, ia_provider=? "
                                        "WHERE id=?",
                                        (_gem_in, _gem_out, _custo['custo_usd'],
                                         _custo['custo_brl'], 'gemini', tx_id)
                                    )
                                    _cost_conn.commit()
                                    print('[COST] gemini in=' + str(_gem_in)
                                          + ' out=' + str(_gem_out)
                                          + ' usd=' + ('%.6f' % _custo['custo_usd'])
                                          + ' brl=' + ('%.4f' % _custo['custo_brl']),
                                          flush=True)
                                finally:
                                    try:
                                        _cost_conn.close()
                                    except Exception:
                                        pass
                        except Exception as _c_e:
                            print('[COST] gemini_update_error tx_id='
                                  + str(tx_id) + ' err=' + str(_c_e), flush=True)
                        _gem_result = {
                            'ok': True,
                            'success': True,
                            'resumo': _gem['resumo'],
                            'estado_geral': _gem.get('estado_geral', 'Bom'),
                            'provider': 'gemini',
                            'balance_after_cents': new_balance,
                            'debited_cents': total_cents,
                            'photos_count': qtd_fotos,
                        }
                        self.write(_gem_result)
                        return
                    print('[GEMINI] fallback_also_failed user=' + user_id
                          + ' err=' + str((_gem or {}).get('error'))[:200],
                          flush=True)
                except Exception as _gem_e:
                    print('[GEMINI] fallback_exception user=' + user_id
                          + ' err=' + str(_gem_e)[:200], flush=True)
                # === FIM FALLBACK GEMINI ===

                # Reembolso: devolve saldo + registra transacao de refund
                try:
                    _conn_rf = get_conn()
                    try:
                        _conn_rf.execute(
                            "UPDATE users SET balance_cents=balance_cents+?, "
                            "updated_at=NOW() WHERE id=?",
                            (total_cents, user_id)
                        )
                        _bal_row = _conn_rf.execute(
                            "SELECT balance_cents FROM users WHERE id=?",
                            (user_id,)
                        ).fetchone()
                        _bal_after = (int(_bal_row['balance_cents'])
                                      if (_bal_row and _bal_row.get(
                                          'balance_cents') is not None)
                                      else 0)
                        _refund_desc = ('Reembolso automatico - IA '
                                        'indisponivel (' + str(qtd_fotos)
                                        + ' foto(s))')
                        _insp_ref2 = (data.get('inspection_id')
                                      or data.get('inspectionId') or None)
                        _conn_rf.execute(
                            "INSERT INTO balance_transactions "
                            "(user_id, type, amount_cents, "
                            " balance_after_cents, description, status, "
                            " analysis_type, photos_count, inspection_id) "
                            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                            (user_id, 'refund', total_cents, _bal_after,
                             _refund_desc, 'completed',
                             tipo_analise, qtd_fotos, _insp_ref2)
                        )
                        _conn_rf.commit()
                        print('[BILLING] refund_ok user=' + user_id
                              + ' total_cents=' + str(total_cents)
                              + ' new_balance=' + str(_bal_after),
                              flush=True)
                    finally:
                        _conn_rf.close()
                except Exception as _rf_e:
                    print('[BILLING] refund_error user=' + user_id
                          + ' err=' + str(_rf_e), flush=True)

                self.set_status(503)
                self.write({
                    'ok': False,
                    'success': False,
                    'code': 'ia_unavailable',
                    'error': ('A IA esta temporariamente sobrecarregada. '
                              'Seu saldo foi estornado automaticamente. '
                              'Tente novamente em alguns instantes.'),
                    'refunded_cents': total_cents,
                })
                return

            if isinstance(resultado, dict):
                resultado['balance_after_cents'] = new_balance
                resultado['debited_cents'] = total_cents
                resultado['photos_count'] = qtd_fotos
                # Calcular e gravar custo IA (task #71) — Claude path
                try:
                    _prov = resultado.get('provider') or 'claude'
                    _model = resultado.get('model') or 'claude-sonnet-4-6'
                    _in_t = int(resultado.get('input_tokens') or 0)
                    _out_t = int(resultado.get('output_tokens') or 0)
                    if tx_id and (_in_t or _out_t):
                        _cost_conn = get_conn()
                        try:
                            _custo = calcular_custo_ia(_prov, _model, _in_t, _out_t, _cost_conn)
                            _cost_conn.execute(
                                "UPDATE balance_transactions SET "
                                "  ia_input_tokens=?, ia_output_tokens=?, "
                                "  ia_custo_usd=?, ia_custo_brl=?, ia_provider=? "
                                "WHERE id=?",
                                (_in_t, _out_t, _custo['custo_usd'],
                                 _custo['custo_brl'], _prov, tx_id)
                            )
                            _cost_conn.commit()
                            print('[COST] ' + _prov + ' in=' + str(_in_t)
                                  + ' out=' + str(_out_t)
                                  + ' usd=' + ('%.6f' % _custo['custo_usd'])
                                  + ' brl=' + ('%.4f' % _custo['custo_brl']),
                                  flush=True)
                        finally:
                            try:
                                _cost_conn.close()
                            except Exception:
                                pass
                except Exception as _c_e:
                    print('[COST] update_error tx_id=' + str(tx_id)
                          + ' err=' + str(_c_e), flush=True)
            self.write(resultado)
        except Exception as e:
            self.set_status(500)
            self.write({"error": str(e), "success": False})


