class GeneratePDFHandler(BaseHandler):
    def get(self, insp_id):
        user = self.require_auth()
        if not user:
            return

        conn = get_conn()
        try:
            insp = conn.execute(
                'SELECT * FROM inspections WHERE id=? AND user_id=?',
                (insp_id, user['user_id'])).fetchone()
            if not insp:
                return self.err('Vistoria nao encontrada', 404)

            inspection_data = self.row_to_dict(insp)

            # Busca ambientes e itens
            rooms = conn.execute(
                'SELECT * FROM rooms WHERE inspection_id=? ORDER BY order_num', (insp_id,)).fetchall()
            rooms_list = []
            for room in rooms:
                room_dict = self.row_to_dict(room)
                items = conn.execute(
                    'SELECT * FROM room_items WHERE room_id=? ORDER BY created_at',
                    (room['id'],)).fetchall()
                room_dict['items'] = self.rows_to_list(items)
                rooms_list.append(room_dict)

            # Busca assinaturas
            sigs = conn.execute(
                'SELECT * FROM signatures WHERE inspection_id=?', (insp_id,)).fetchall()
            signatures_list = self.rows_to_list(sigs)

            # Gera PDF
            tipo = inspection_data.get('type', 'entrada')
            pdf_filename = f"IZYLO_Laudo_{tipo}_{insp_id[:8].upper()}.pdf"
            pdf_path = os.path.join(PDF_DIR, pdf_filename)

            success = generate_pdf(inspection_data, rooms_list, signatures_list, pdf_path)

            if not success:
                return self.err('Erro ao gerar PDF', 500)

            # Marca como concluÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ­do
            # --- Save complete laudo data (GET, safe) ---
            import logging as _logging
            import traceback as _tb_mod
            _logging.warning(f'[PDF-SAVE-GET] insp_id={insp_id!r}')
            try:
                _tipo_c = (inspection_data.get('type') or 'entrada').lower()
                _prefixo_c = 'VE' if _tipo_c == 'entrada' else ('VS' if _tipo_c == 'saida' else 'VE')
                try:
                    _dt_c = inspection_data.get('inspection_date') or inspection_data.get('created_at') or ''
                    _ano_c = int(_dt_c[:4]) if len(_dt_c) >= 4 else datetime.now().year
                except Exception:
                    _ano_c = datetime.now().year
                _codigo = f'{_prefixo_c}-{_ano_c}-{str(insp_id)[:4].upper()}'
                conn.execute("UPDATE inspections SET status='concluido', codigo=?, updated_at=? WHERE id=?",
                    (_codigo, datetime.now().strftime('%Y-%m-%d %H:%M:%S'), insp_id))
                conn.commit()
                _logging.warning(f'[PDF-SAVE-GET] COMMIT OK codigo={_codigo}')
            except Exception as _save_err:
                _logging.warning(f'[PDF-SAVE-GET] ERRO: {_save_err}')
                _logging.warning(f'[PDF-SAVE-GET] TRACEBACK: {_tb_mod.format_exc()}')
                try:
                    conn.rollback()
                except Exception:
                    pass
            self.set_header('Content-Type', 'application/pdf')
            self.set_header('Content-Disposition', f'attachment; filename="{pdf_filename}"')
            with open(pdf_path, 'rb') as f:
                self.write(f.read())
            self.finish()
        finally:
            conn.close()


    def post(self, insp_id):
        try:
            user = self.require_auth()
            if not user:
                return
            body = self.json_body() or {}
            amb_data = body.get('ambData', [])
            amb_by_name = {a.get('roomName', ''): a for a in amb_data}
            _wiz_snap = body.get('wizard_snapshot') or body.get('wizardSnapshot')
            if _wiz_snap is not None and not isinstance(_wiz_snap, str):
                try:
                    _wiz_snap = __import__('json').dumps(_wiz_snap, ensure_ascii=False)
                except Exception:
                    _wiz_snap = None
            conn = get_conn()
            try:
                insp = conn.execute(
                    'SELECT * FROM inspections WHERE id=? AND user_id=?',
                    (insp_id, user['user_id'])).fetchone()
                if not insp:
                    return self.err('Vistoria nao encontrada', 404)
                inspection_data = self.row_to_dict(insp)
                rooms = conn.execute(
                    'SELECT * FROM rooms WHERE inspection_id=? ORDER BY order_num', (insp_id,)).fetchall()
                rooms_list = []
                for room in rooms:
                    room_dict = self.row_to_dict(room)
                    items = conn.execute(
                        'SELECT * FROM room_items WHERE room_id = ? ORDER BY created_at',
                        (room['id'],)).fetchall()
                    room_dict['items'] = self.rows_to_list(items)
                    # Match by name only (positional match caused cross-contamination).
                    amb = amb_by_name.get(room_dict.get('name', ''), {}) or None
                    if amb:
                        room_dict['verificacoes'] = amb.get('verificacoes', {})
                        room_dict['verificacoes_obs'] = amb.get('verificacoesObs', {})
                        room_dict['testes_nomes'] = amb.get('testesNomes', {})
                        room_dict['observacoes'] = amb.get('observacoes', '')
                        # Pass suite/sub-ambiente data through to pdf_service
                        if amb.get('isSuite'):
                            room_dict['isSuite'] = True
                        if amb.get('subAmbientes'):
                            room_dict['subAmbientes'] = amb.get('subAmbientes', [])
                        # Inventario (temporada)
                        room_dict['inventario'] = amb.get('inventario') or {}
                        room_dict['inventarioExtras'] = amb.get('inventarioExtras') or []
                        room_dict['inventarioNomes'] = amb.get('inventarioNomes') or []
                        room_dict['consolidated_text'] = amb.get('consolidated_text') or amb.get('consolidatedText') or room_dict.get('consolidated_text') or ''
                        room_dict['amb_photos'] = amb.get('photos') or []
                        print('[DEBUG inv]', room_dict.get('inventarioNomes', [])[:2], 'inv keys:', list(room_dict.get('inventario', {}).keys())[:5])
                    rooms_list.append(room_dict)
                sigs = conn.execute(
                    'SELECT * FROM signatures WHERE inspection_id=?', (insp_id,)).fetchall()
                signatures_list = self.rows_to_list(sigs)
                tipo = inspection_data.get('type', 'entrada')
                pdf_filename = f"IZYLO_Laudo_{tipo}_{insp_id[:8].upper()}.pdf"
                pdf_path = os.path.join(PDF_DIR, pdf_filename)
                success = generate_pdf(inspection_data, rooms_list, signatures_list, pdf_path)
                if not success:
                    return self.err('Erro ao gerar PDF', 500)
                # --- Save complete laudo data (safe) ---
                import logging as _logging
                import traceback as _tb_mod
                _json_mod = __import__('json')
                # Log payload structure
                _logging.warning(f'[PDF-SAVE] insp_id={insp_id!r} type={type(insp_id).__name__}')
                _logging.warning(f'[PDF-SAVE] rooms_list count={len(rooms_list)}')
                _logging.warning(f'[PDF-SAVE] amb_data count={len(amb_data) if amb_data else 0}')
                if amb_data and len(amb_data) > 0:
                    _a0 = amb_data[0]
                    _logging.warning(f'[PDF-SAVE] amb[0] keys={list(_a0.keys()) if isinstance(_a0, dict) else type(_a0)}')
                    _logging.warning(f'[PDF-SAVE] amb[0] observacoes={str(_a0.get("observacoes",""))[:100] if isinstance(_a0, dict) else "N/A"}')
                if rooms_list and len(rooms_list) > 0:
                    _r0 = rooms_list[0]
                    _logging.warning(f'[PDF-SAVE] room[0] keys={list(_r0.keys())[:15]}')
                    _logging.warning(f'[PDF-SAVE] room[0] id={_r0.get("id","?")[:12]}')
                    _logging.warning(f'[PDF-SAVE] room[0] consolidated_text={str(_r0.get("consolidated_text",""))[:100]}')
                    _logging.warning(f'[PDF-SAVE] room[0] observacoes={str(_r0.get("observacoes",""))[:100]}')
                    _logging.warning(f'[PDF-SAVE] room[0] general_condition={str(_r0.get("general_condition",""))[:100]}')
                    _logging.warning(f'[PDF-SAVE] room[0] verificacoes type={type(_r0.get("verificacoes")).__name__}')
                try:
                    _tipo_c = (inspection_data.get('type') or 'entrada').lower()
                    _prefixo_c = 'VE' if _tipo_c == 'entrada' else ('VS' if _tipo_c == 'saida' else 'VE')
                    try:
                        _dt_c = inspection_data.get('inspection_date') or inspection_data.get('created_at') or ''
                        _ano_c = int(_dt_c[:4]) if len(_dt_c) >= 4 else datetime.now().year
                    except Exception:
                        _ano_c = datetime.now().year
                    _codigo = f'{_prefixo_c}-{_ano_c}-{str(insp_id)[:4].upper()}'
                    _logging.warning(f'[PDF-SAVE] codigo={_codigo}')
                    conn.execute("UPDATE inspections SET status='concluido', codigo=?, updated_at=? WHERE id=?",
                        (_codigo, datetime.now().strftime('%Y-%m-%d %H:%M:%S'), insp_id))
                    _logging.warning('[PDF-SAVE] inspection UPDATE ok')
                    for _ri, _room in enumerate(rooms_list):
                        _room_id = _room.get('id')
                        if not _room_id:
                            continue
                        _obs = _room.get('observacoes') or _room.get('observations') or ''
                        _gc = _room.get('general_condition') or ''
                        _ct = _room.get('consolidated_text') or ''
                        # FALLBACK: se consolidated_text vazio, montar dos itens
                        if not _ct:
                            _items_list = _room.get('items') or []
                            _descs = []
                            for _it in _items_list:
                                _it_desc = _it.get('manual_description') or _it.get('ai_description') or ''
                                if _it_desc:
                                    _it_name = _it.get('name') or _it.get('item_name') or ''
                                    _descs.append((_it_name + ': ' + _it_desc) if _it_name else _it_desc)
                            if not _descs:
                                # Fallback 2: buscar do banco
                                try:
                                    _db_items = conn.execute(
                                        'SELECT name, ai_description, manual_description FROM room_items WHERE room_id=? ORDER BY created_at',
                                        (_room_id,)).fetchall()
                                    for _dbi in _db_items:
                                        _dbi_desc = (_dbi['manual_description'] if _dbi['manual_description'] else None) or (_dbi['ai_description'] if _dbi['ai_description'] else None) or ''
                                        if _dbi_desc:
                                            _dbi_name = _dbi['name'] or ''
                                            _descs.append((_dbi_name + ': ' + _dbi_desc) if _dbi_name else _dbi_desc)
                                except Exception:
                                    pass
                            _ct = '\n'.join(_descs)
                            if _ct:
                                _logging.warning(f'[PDF-SAVE] fallback consolidated_text for room {_room_id}: {_ct[:80]}')
                        _vrf = _room.get('verificacoes') or {}
                        _vrf_j = _json_mod.dumps(_vrf) if isinstance(_vrf, dict) else str(_vrf)
                        conn.execute("UPDATE rooms SET observations=?, general_condition=?, consolidated_text=?, verificacoes_json=? WHERE id=? AND inspection_id=?",
                            (_obs, _gc, _ct, _vrf_j, _room_id, insp_id))
                        if _ri == 0:
                            _logging.warning(f'[PDF-SAVE] room[0] UPDATE ok obs_len={len(_obs)} gc_len={len(_gc)} ct_len={len(_ct)} vrf_len={len(_vrf_j)}')
                        # Save ai_description for each photo
                        _amb_photos = _room.get('amb_photos') or []
                        for _ph in _amb_photos:
                            _pid = _ph.get('id')
                            _p_aid = _ph.get('ai_description') or ''
                            if _pid and _p_aid:
                                try:
                                    conn.execute("UPDATE item_photos SET ai_description=? WHERE id=?", (_p_aid, _pid))
                                except Exception:
                                    pass
                    if _wiz_snap is not None:
                        try:
                            conn.execute("UPDATE inspections SET wizard_snapshot=? WHERE id=?", (_wiz_snap, insp_id))
                        except Exception:
                            pass
                    conn.commit()
                    _logging.warning(f'[PDF-SAVE] COMMIT OK for {insp_id}')
                except Exception as _save_err:
                    _logging.warning(f'[PDF-SAVE] ERRO: {_save_err}')
                    _logging.warning(f'[PDF-SAVE] TRACEBACK: {_tb_mod.format_exc()}')
                    try:
                        conn.rollback()
                    except Exception:
                        pass
                self.set_header('Content-Type', 'application/pdf')
                self.set_header('Content-Disposition',
                    f'attachment; filename="{pdf_filename}"')
                with open(pdf_path, 'rb') as f:
                    self.write(f.read())
                self.finish()
            finally:
                conn.close()
        except Exception as e:
            import traceback
            tb = traceback.format_exc()
            print('[PDF HANDLER ERROR]', str(e), flush=True)
            print('[PDF HANDLER TRACEBACK]', tb, flush=True)
            try:
                self.set_status(500)
                self.write({'error': str(e), 'type': type(e).__name__, 'traceback': tb})
            except Exception:
                pass
            return

