        idx = os.path.join(static_dir, 'index.html')
        try:
            with open(idx, 'rb') as f:
                self.set_header('Content-Type', 'text/html; charset=utf-8')
                self.write(f.read())
        except Exception as e:
            self.set_status(500)
            self.write('Erro carregando pagina: ' + str(e))


