class LaudoStatusHandler(BaseHandler):
    """POST /laudo/<id>/status -> atualiza status do laudo."""
    def post(self, insp_id):
        user = self.require_auth()
        if not user:
            return
        try:
            body = json.loads(self.request.body or b'{}')
        except Exception:
            body = {}
        new_status = (body.get('status') or '').strip()
        data_assinatura = body.get('data_assinatura')
        allowed = {'em_andamento', 'concluido', 'aguardando_assinatura', 'assinado', 'assinado_digital', 'assinado_fisico'}
        if new_status not in allowed:
            self.set_status(400)
            self.write(json.dumps({'error': 'Status invalido'}))
            return
        conn = get_conn()
        try:
            row = conn.execute('SELECT id FROM inspections WHERE id=? AND user_id=?', (insp_id, user['user_id'])).fetchone()
            if not row:
                self.set_status(404)
                self.write(json.dumps({'error': 'Laudo nao encontrado'}))
                return
            if data_assinatura:
                conn.execute('UPDATE inspections SET status=?, data_assinatura=? WHERE id=?', (new_status, data_assinatura, insp_id))
            else:
                conn.execute('UPDATE inspections SET status=? WHERE id=?', (new_status, insp_id))
            conn.commit()
            self.write(json.dumps({'ok': True, 'status': new_status}))
        finally:
            conn.close()


class LaudoDeleteHandler(BaseHandler):
    """DELETE /laudo/<id> -> exclui o laudo permanentemente."""
    def delete(self, insp_id):
        user = self.require_auth()
        if not user:
            return
        conn = get_conn()
        try:
            row = conn.execute('SELECT id FROM inspections WHERE id=? AND user_id=?', (insp_id, user['user_id'])).fetchone()
            if not row:
                self.set_status(404)
                self.write(json.dumps({'error': 'Laudo nao encontrado'}))
                return
            try:
                conn.execute('DELETE FROM room_items WHERE room_id IN (SELECT id FROM rooms WHERE inspection_id=?)', (insp_id,))
            except Exception:
                pass
            try:
                conn.execute('DELETE FROM rooms WHERE inspection_id=?', (insp_id,))
            except Exception:
                pass
            conn.execute('DELETE FROM inspections WHERE id=?', (insp_id,))
            conn.commit()
            self.write(json.dumps({'ok': True}))
        finally:
            conn.close()


class LaudoBulkDeleteHandler(BaseHandler):
    """POST /laudo/bulk-delete -> exclui multiplos laudos. Body: {"ids":[...]} ou {"all":true}."""
    def post(self):
        user = self.require_auth()
        if not user:
            return
        try:
            body = json.loads(self.request.body or b"{}")
        except Exception:
            body = {}
        ids = body.get("ids") or []
        delete_all = bool(body.get("all"))
        if not isinstance(ids, list):
            ids = []
        conn = get_conn()
        deleted = 0
        try:
            if delete_all:
                rows = conn.execute("SELECT id FROM inspections WHERE user_id=?", (user["user_id"],)).fetchall()
                target_ids = [r[0] if not hasattr(r,"keys") else r["id"] for r in rows]
            else:
                target_ids = []
                for iid in ids:
                    if not iid: continue
                    row = conn.execute("SELECT id FROM inspections WHERE id=? AND user_id=?", (iid, user["user_id"])).fetchone()
                    if row: target_ids.append(iid)
            for iid in target_ids:
                try:
                    conn.execute("DELETE FROM room_items WHERE room_id IN (SELECT id FROM rooms WHERE inspection_id=?)", (iid,))
                except Exception:
                    pass
                try:
                    conn.execute("DELETE FROM rooms WHERE inspection_id=?", (iid,))
                except Exception:
                    pass
                conn.execute("DELETE FROM inspections WHERE id=?", (iid,))
                deleted += 1
            conn.commit()
            self.write(json.dumps({"ok": True, "deleted": deleted}))
        except Exception as e:
            self.set_status(500)
            self.write(json.dumps({"ok": False, "error": str(e)}))
        finally:
            conn.close()


