# ─── Autentique: envio de laudo para assinatura digital ──────────────────────
class SendToAutentiqueHandler(BaseHandler):
    def post(self, inspection_id):
        user = self.require_auth()
        if not user:
            return

        user_id = user['user_id']
        conn = get_conn()
        try:
            # 1. Buscar inspeção
            insp_row = conn.execute(
                "SELECT * FROM inspections WHERE id=? AND user_id=?",
                (inspection_id, user_id)
            ).fetchone()
            if not insp_row:
                return self.err('Laudo nao encontrado', 404)
            insp = self.row_to_dict(insp_row)

            # 2. Verificar se já foi enviado
            if insp.get('autentique_doc_id'):
                return self.err(
                    'Este laudo ja foi enviado para assinatura',
                    400
                )

            # 3. Montar lista de signatarios a partir dos campos/JSONs da inspeção
            signers = []
            seen_emails = set()

            def _add_signer(name, email):
                if not email:
                    return
                e = str(email).strip().lower()
                if not e or '@' not in e or e in seen_emails:
                    return
                seen_emails.add(e)
                signers.append({
                    'email': str(email).strip(),
                    'name': (name or '').strip() or (email or '').split('@')[0],
                    'action': 'SIGN',
                })

            # DEBUG: ver conteúdo raw dos JSONs antes da extração
            _dbg_locs_raw = insp.get('locadores_json')
            _dbg_locsat_raw = insp.get('locatarios_json')
            print('[AUTENTIQUE_DEBUG] locadores_json raw: '
                  + repr(_dbg_locs_raw)[:500], flush=True)
            print('[AUTENTIQUE_DEBUG] locatarios_json raw: '
                  + repr(_dbg_locsat_raw)[:500], flush=True)
            print('[AUTENTIQUE_DEBUG] legacy fields: locador_name='
                  + repr(insp.get('locador_name'))
                  + ' locador_email=' + repr(insp.get('locador_email'))
                  + ' locatario_name=' + repr(insp.get('locatario_name'))
                  + ' locatario_email=' + repr(insp.get('locatario_email'))
                  + ' corretor_name=' + repr(insp.get('corretor_name'))
                  + ' corretor_email=' + repr(insp.get('corretor_email'))
                  + ' imob_name=' + repr(insp.get('imobiliaria_name'))
                  + ' imob_email=' + repr(insp.get('imobiliaria_email')),
                  flush=True)

            # Locadores do JSON
            try:
                locs_json = _dbg_locs_raw or '[]'
                locs = json.loads(locs_json) if isinstance(locs_json, str) else locs_json
                if isinstance(locs, list):
                    for p in locs:
                        if isinstance(p, dict):
                            _add_signer(p.get('name') or p.get('nome'),
                                        p.get('email'))
            except Exception as _e_loc:
                print('[AUTENTIQUE_DEBUG] locs parse err: ' + str(_e_loc),
                      flush=True)

            # Locatarios do JSON
            try:
                locsat_json = _dbg_locsat_raw or '[]'
                locsat = json.loads(locsat_json) if isinstance(locsat_json, str) else locsat_json
                if isinstance(locsat, list):
                    for p in locsat:
                        if isinstance(p, dict):
                            _add_signer(p.get('name') or p.get('nome'),
                                        p.get('email'))
            except Exception as _e_lct:
                print('[AUTENTIQUE_DEBUG] locsat parse err: ' + str(_e_lct),
                      flush=True)

            # Fallback: campos diretos (legacy)
            _add_signer(insp.get('locador_name'), insp.get('locador_email'))
            _add_signer(insp.get('locatario_name'), insp.get('locatario_email'))
            # Corretor e imobiliaria
            _add_signer(insp.get('corretor_name'), insp.get('corretor_email'))
            _add_signer(insp.get('imobiliaria_name'), insp.get('imobiliaria_email'))

            print('[AUTENTIQUE_DEBUG] signers final: '
                  + repr(signers)[:500], flush=True)

            if not signers:
                return self.err(
                    'Nenhum signatario com email encontrado. Cadastre os emails '
                    'das partes na etapa 4.',
                    400
                )

            # 4. Gerar PDF do laudo (reusa generate_pdf do pdf_service)
            pdf_bytes = self._gerar_pdf_bytes(conn, insp)
            if not pdf_bytes:
                return self.err('Erro ao gerar PDF do laudo', 500)

            # 5. Nome do documento
            tipo_v = (insp.get('type') or 'entrada').capitalize()
            address = insp.get('property_address') or insp.get('address') or 'Laudo'
            doc_name = 'Laudo de Vistoria - ' + tipo_v + ' - ' + address
            # Autentique tem limite de 255 chars
            if len(doc_name) > 250:
                doc_name = doc_name[:250]

            # 6. Chamar API Autentique (GraphQL multipart)
            import requests as _req

            query = (
                'mutation CreateDocumentMutation('
                '$document: DocumentInput!, '
                '$signers: [SignerInput!]!, '
                '$file: Upload!'
                ') { createDocument(document: $document, signers: $signers, '
                'file: $file) { id name signatures { public_id name email '
                'link { short_link } } } }'
            )

            variables = {
                'document': {
                    'name': doc_name,
                    'message': 'Por favor, assine o laudo de vistoria do imovel.',
                },
                'signers': signers,
                'file': None,
            }

            operations = json.dumps({'query': query, 'variables': variables},
                                    ensure_ascii=False)
            map_field = json.dumps({'file': ['variables.file']})

            try:
                resp = _req.post(
                    'https://api.autentique.com.br/v2/graphql',
                    headers={'Authorization': 'Bearer ' + AUTENTIQUE_TOKEN},
                    data={'operations': operations, 'map': map_field},
                    files={'file': (
                        'laudo_' + inspection_id + '.pdf',
                        pdf_bytes,
                        'application/pdf'
                    )},
                    timeout=60
                )
            except Exception as _net_e:
                print('[AUTENTIQUE] NET_ERROR: ' + str(_net_e), flush=True)
                return self.err('Falha de conexao com Autentique: '
                                + str(_net_e), 502)

            try:
                result = resp.json()
            except Exception:
                print('[AUTENTIQUE] invalid_json status=' + str(resp.status_code)
                      + ' body=' + str(resp.text[:500]), flush=True)
                return self.err(
                    'Resposta invalida do Autentique (status '
                    + str(resp.status_code) + ')', 502)

            if 'errors' in result:
                print('[AUTENTIQUE] GQL_ERRORS: '
                      + json.dumps(result.get('errors'))[:500], flush=True)
                msg = 'Erro no Autentique'
                try:
                    msg = result['errors'][0].get('message', msg)
                except Exception:
                    pass
                return self.err(msg, 502)

            doc = (result.get('data') or {}).get('createDocument') or {}
            autentique_id = doc.get('id')
            if not autentique_id:
                return self.err('Autentique nao retornou id do documento', 502)

            # 7. Atualizar inspecao (status 'aguardando_assinatura' casa com
            #    o que o frontend espera em _mlStatusKey — label
            #    'Aguard. assinatura').
            conn.execute(
                "UPDATE inspections SET "
                "autentique_doc_id=?, "
                "autentique_status='sent', "
                "autentique_sent_at=NOW(), "
                "status='aguardando_assinatura', "
                "updated_at=? "
                "WHERE id=? AND user_id=?",
                (str(autentique_id),
                 datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                 inspection_id, user_id)
            )
            conn.commit()

            print('[AUTENTIQUE] OK user=' + user_id + ' insp=' + inspection_id
                  + ' doc=' + str(autentique_id)
                  + ' signers=' + str(len(signers)), flush=True)

            self.ok({
                'sent': True,
                'autentique_doc_id': autentique_id,
                'doc_name': doc_name,
                'signers_count': len(signers),
                'signatures': doc.get('signatures', []),
            })

        except Exception as e:
            try:
                conn.rollback()
            except Exception:
                pass
            print('[AUTENTIQUE] ERROR user=' + str(user.get('user_id')) + ': '
                  + str(e), flush=True)
            return self.err('Erro ao enviar para Autentique: ' + str(e), 500)
        finally:
            try:
                conn.close()
            except Exception:
                pass

    def _gerar_pdf_bytes(self, conn, insp):
        """Reusa generate_pdf() do pdf_service para gerar o PDF em disco e
        retornar os bytes. Mesma logica do GeneratePDFHandler.get()."""
        try:
            from pdf_service import generate_pdf as _gen_pdf
        except Exception as _e:
            print('[AUTENTIQUE] pdf_service import fail: ' + str(_e), flush=True)
            return None
        try:
            insp_id = insp.get('id')
            rooms = conn.execute(
                'SELECT * FROM rooms WHERE inspection_id=? ORDER BY order_num',
                (insp_id,)
            ).fetchall()
            rooms_list = []
            for room in rooms:
                room_dict = self.row_to_dict(room)
                items = conn.execute(
                    'SELECT * FROM room_items WHERE room_id=? ORDER BY created_at',
                    (room['id'],)
                ).fetchall()
                room_dict['items'] = self.rows_to_list(items)
                rooms_list.append(room_dict)
            sigs = conn.execute(
                'SELECT * FROM signatures WHERE inspection_id=?',
                (insp_id,)
            ).fetchall()
            signatures_list = self.rows_to_list(sigs)

            tipo = (insp.get('type') or 'entrada')
            pdf_filename = ('IZYLO_Laudo_autentique_' + str(tipo) + '_'
                            + str(insp_id)[:8].upper() + '.pdf')
            pdf_path = os.path.join(PDF_DIR, pdf_filename)
            ok = _gen_pdf(insp, rooms_list, signatures_list, pdf_path)
            if not ok or not os.path.exists(pdf_path):
                return None
            with open(pdf_path, 'rb') as f:
                return f.read()
        except Exception as _e:
            print('[AUTENTIQUE] PDF_ERROR: ' + str(_e), flush=True)
            return None


class AutentiqueWebhookHandler(BaseHandler):
    """Recebe notificacao do Autentique quando o documento for assinado."""
    def post(self):
        try:
            # Log de headers para identificar qual campo traz o secret
            try:
                _hdrs = {}
                for k, v in self.request.headers.items():
                    _hdrs[k] = v
                print('[AUTENTIQUE_WEBHOOK] headers: '
                      + json.dumps(_hdrs)[:800], flush=True)
            except Exception:
                pass

            # Validar assinatura HMAC-SHA256 (formato real do Autentique).
            # O Autentique envia X-Autentique-Signature = hex(hmac_sha256(
            # secret, raw_body)). Ainda aceitamos tokens planos nos nomes
            # antigos como fallback, caso a configuracao mude.
            WEBHOOK_SECRET = os.environ.get('AUTENTIQUE_WEBHOOK_SECRET', '')
            if WEBHOOK_SECRET:
                raw_body = self.request.body or b''
                import hmac as _hmac
                import hashlib as _hashlib
                expected_sig = _hmac.new(
                    WEBHOOK_SECRET.encode('utf-8'),
                    raw_body,
                    _hashlib.sha256
                ).hexdigest()
                got_sig = (self.request.headers.get('X-Autentique-Signature')
                           or '').strip().lower()
                # Fallback: aceita tambem bearer plain caso futuro
                got_plain = (
                    self.request.headers.get('X-Autentique-Token')
                    or self.request.headers.get('X-Autentique-Secret')
                    or self.request.headers.get('X-Webhook-Secret')
                    or self.request.headers.get('Authorization', '').replace(
                        'Bearer ', '').strip()
                    or ''
                )
                sig_ok = (got_sig and _hmac.compare_digest(
                    got_sig, expected_sig.lower()))
                plain_ok = (got_plain and _hmac.compare_digest(
                    got_plain, WEBHOOK_SECRET))
                if not (sig_ok or plain_ok):
                    print('[AUTENTIQUE_WEBHOOK] Invalid secret - rejecting '
                          'got_sig=' + (got_sig[:12] + '...' if got_sig
                                        else 'empty')
                          + ' expected_sig=' + expected_sig[:12] + '...'
                          + ' got_plain_tier=' + ('present' if got_plain
                                                  else 'empty'),
                          flush=True)
                    self.set_status(401)
                    self.write({'ok': False, 'error': 'Invalid signature'})
                    return

            data = self.json_body() or {}
            print('[AUTENTIQUE_WEBHOOK] received: '
                  + json.dumps(data)[:800], flush=True)

            event = (data.get('event') or '').strip()
            doc = data.get('document') or {}
            doc_id = doc.get('id') or data.get('document_id') or ''

            if not doc_id:
                self.write({'ok': True})
                return

            # document.finished e as variantes que ja aceitavamos
            finished_events = (
                'document.finished', 'document_finished',
                'document_signed', 'document.signed',
                'signed', 'finished'
            )
            if event in finished_events:
                conn = get_conn()
                try:
                    # 'assinado_digital' eh o valor que o frontend reconhece
                    # em _mlStatusKey -> label 'Assinado digital'
                    conn.execute(
                        "UPDATE inspections SET "
                        "autentique_status='signed', "
                        "status='assinado_digital', "
                        "updated_at=? "
                        "WHERE autentique_doc_id=?",
                        (datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                         str(doc_id))
                    )
                    conn.commit()
                    print('[AUTENTIQUE_WEBHOOK] signed doc=' + str(doc_id)
                          + ' event=' + event, flush=True)
                finally:
                    try: conn.close()
                    except Exception: pass

            self.write({'ok': True})
        except Exception as e:
            print('[AUTENTIQUE_WEBHOOK] ERROR: ' + str(e), flush=True)
            # Sempre 200 para nao fazer o Autentique reenviar
            self.write({'ok': True})


# ─── Extrato Financeiro ──────────────────────────────────────────────────────

_EXTRATO_PERIODO_SQL = {
    'mes':  "AND created_at >= date_trunc('month', NOW())",
    '3m':   "AND created_at >= NOW() - INTERVAL '3 months'",
    '6m':   "AND created_at >= NOW() - INTERVAL '6 months'",
    'ano':  "AND created_at >= date_trunc('year', NOW())",
    'tudo': ''
}

_EXTRATO_PERIODO_LABELS = {
    'mes':  'Este mes',
    '3m':   'Ultimos 3 meses',
    '6m':   'Ultimos 6 meses',
    'ano':  'Este ano',
    'tudo': 'Todo o historico'
}


class BillingTransactionsHandler(BaseHandler):
    def get(self):
        user = self.require_auth()
        if not user:
            return
        user_id = user['user_id']
        periodo = self.get_argument('periodo', 'mes')
        periodo_sql = _EXTRATO_PERIODO_SQL.get(periodo,
                                               _EXTRATO_PERIODO_SQL['mes'])

        conn = get_conn()
        try:
            # periodo_sql vem de whitelist; seguro interpolar diretamente.
            # Filtra por status='completed' para nao mostrar recargas
            # pendentes/canceladas/falhadas no extrato.
            sql = (
                "SELECT id, type, amount_cents, balance_after_cents, "
                "description, status, analysis_type, photos_count, "
                "created_at "
                "FROM balance_transactions "
                "WHERE user_id=? AND status='completed' " + periodo_sql + " "
                "ORDER BY created_at DESC"
            )
            rows = conn.execute(sql, (user_id,)).fetchall()
            transactions = self.rows_to_list(rows)

            total_recargas = 0
            total_consumido = 0
            total_fotos = 0
            count_recargas = 0
            for t in transactions:
                # Serialize datetime para string
                if t.get('created_at') is not None and not isinstance(
                        t['created_at'], str):
                    try:
                        t['created_at'] = t['created_at'].isoformat(sep=' ')
                    except Exception:
                        t['created_at'] = str(t['created_at'])
                amt = int(t.get('amount_cents') or 0)

                # Sanitiza descricao de recargas: remove ID interno do MP
                # do formato "Compra de creditos R$ XX,XX|mp:123-abc..."
                desc = t.get('description') or ''
                is_recarga = amt > 0 or (t.get('type') or '') in (
                    'credit', 'recarga', 'mp_credit'
                )
                if is_recarga and ('mp:' in desc or '|mp' in desc
                                   or desc.strip() == ''):
                    t['description'] = 'Recarga via Mercado Pago'

                if amt > 0:
                    total_recargas += amt
                    count_recargas += 1
                elif amt < 0:
                    total_consumido += abs(amt)
                    total_fotos += int(t.get('photos_count') or 0)

            urow = conn.execute(
                "SELECT balance_cents, name, email FROM users WHERE id=?",
                (user_id,)
            ).fetchone()
            balance_cents = int(urow['balance_cents']) if (urow and
                urow.get('balance_cents') is not None) else 0
            user_name = urow['name'] if urow else ''
            user_email = urow['email'] if urow else ''

            self.ok({
                'transactions': transactions,
                'user': {'name': user_name, 'email': user_email},
                'resumo': {
                    'total_recargas_cents': total_recargas,
                    'total_consumido_cents': total_consumido,
                    'total_fotos': total_fotos,
                    'count_recargas': count_recargas,
                    'balance_cents': balance_cents,
                },
                'periodo': periodo,
            })
        finally:
            conn.close()


class BillingTransactionsPDFHandler(BaseHandler):
    def get(self):
        # require_auth aceita ?token=... (ver BaseHandler.get_current_user)
        user = self.require_auth()
        if not user:
            return
        user_id = user['user_id']
        periodo = self.get_argument('periodo', 'mes')
        periodo_sql = _EXTRATO_PERIODO_SQL.get(periodo,
                                               _EXTRATO_PERIODO_SQL['mes'])

        conn = get_conn()
        try:
            # Filtra status='completed' - mesma regra do endpoint JSON
            sql = (
                "SELECT amount_cents, balance_after_cents, description, "
                "analysis_type, photos_count, created_at, type "
                "FROM balance_transactions "
                "WHERE user_id=? AND status='completed' " + periodo_sql + " "
                "ORDER BY created_at DESC"
            )
            rows_raw = conn.execute(sql, (user_id,)).fetchall()
            rows = [self.row_to_dict(r) for r in rows_raw]
            # Sanitiza descricao das recargas (remove ID interno do MP)
            for _rr in rows:
                _amt = int(_rr.get('amount_cents') or 0)
                _desc = _rr.get('description') or ''
                _is_rec = _amt > 0 or (_rr.get('type') or '') in (
                    'credit', 'recarga', 'mp_credit')
                if _is_rec and ('mp:' in _desc or '|mp' in _desc
                                or _desc.strip() == ''):
                    _rr['description'] = 'Recarga via Mercado Pago'

            urow = conn.execute(
                "SELECT balance_cents, name, email FROM users WHERE id=?",
                (user_id,)
            ).fetchone()
            balance_cents = int(urow['balance_cents']) if (urow and
                urow.get('balance_cents') is not None) else 0
            user_name = urow['name'] if urow else ''
            user_email = urow['email'] if urow else ''
        finally:
            conn.close()

        from reportlab.lib.pagesizes import A4
        from reportlab.lib import colors
        from reportlab.platypus import (SimpleDocTemplate, Table, TableStyle,
                                         Paragraph, Spacer)
        from reportlab.lib.styles import ParagraphStyle
        from reportlab.lib.units import cm
        import io

        buffer = io.BytesIO()
        doc = SimpleDocTemplate(buffer, pagesize=A4,
                                rightMargin=2*cm, leftMargin=2*cm,
                                topMargin=2*cm, bottomMargin=2*cm)

        story = []
        # Espacamento vertical explicito entre titulo e subtitulos para evitar
        # sobreposicao (observado em preview de alguns leitores PDF).
        title_style = ParagraphStyle(
            'title', fontSize=18, fontName='Helvetica-Bold',
            leading=22,
            textColor=colors.HexColor('#1e3a5f'), spaceAfter=12)
        sub_style = ParagraphStyle(
            'sub', fontSize=10, leading=14,
            textColor=colors.HexColor('#64748b'),
            spaceAfter=4)

        story.append(Paragraph('izyLAUDO - Extrato Financeiro', title_style))
        story.append(Spacer(1, 0.3 * cm))
        story.append(Paragraph(
            'Periodo: ' + _EXTRATO_PERIODO_LABELS.get(periodo, periodo),
            sub_style))
        story.append(Paragraph(
            'Usuario: ' + (user_name or '') + ' (' + (user_email or '') + ')',
            sub_style))
        story.append(Paragraph(
            'Gerado em: ' + datetime.now(TZ_BR).strftime('%d/%m/%Y %H:%M'),
            sub_style))
        story.append(Spacer(1, 0.5*cm))

        total_rec = sum(int(r.get('amount_cents') or 0)
                         for r in rows if int(r.get('amount_cents') or 0) > 0)
        total_cons = sum(abs(int(r.get('amount_cents') or 0))
                          for r in rows if int(r.get('amount_cents') or 0) < 0)

        def _fmt_brl(cents):
            return 'R$ ' + ('%.2f' % (cents / 100.0)).replace('.', ',')

        resumo_data = [
            ['Total recarregado', 'Total consumido', 'Saldo atual'],
            [_fmt_brl(total_rec), _fmt_brl(total_cons),
             _fmt_brl(balance_cents)]
        ]
        resumo_table = Table(resumo_data,
                              colWidths=[5.5*cm, 5.5*cm, 5.5*cm])
        resumo_table.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#f8fafc')),
            ('TEXTCOLOR', (0, 0), (-1, 0), colors.HexColor('#64748b')),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 0), (-1, -1), 9),
            ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
            ('TEXTCOLOR', (0, 1), (0, 1), colors.HexColor('#15803d')),
            ('TEXTCOLOR', (1, 1), (1, 1), colors.HexColor('#dc2626')),
            ('FONTNAME', (0, 1), (-1, 1), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 1), (-1, 1), 12),
            ('BOX', (0, 0), (-1, -1), 0.5, colors.HexColor('#e2e8f0')),
            ('INNERGRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#e2e8f0')),
            ('TOPPADDING', (0, 0), (-1, -1), 8),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 8),
        ]))
        story.append(resumo_table)
        story.append(Spacer(1, 0.5*cm))

        table_data = [['Data', 'Descricao', 'Tipo', 'Valor', 'Saldo']]
        for r in rows:
            dt = r.get('created_at')
            if hasattr(dt, 'strftime'):
                data_str = dt.strftime('%d/%m/%Y %H:%M')
            else:
                data_str = str(dt)[:16] if dt else ''
            amt = int(r.get('amount_cents') or 0)
            is_rec = amt > 0
            tipo = 'Recarga' if is_rec else (
                'Premium' if r.get('analysis_type') == 'premium'
                else 'Convencional')
            valor = ('+ ' if is_rec else '- ') + _fmt_brl(abs(amt))
            saldo = _fmt_brl(int(r.get('balance_after_cents') or 0))
            desc = r.get('description') or tipo
            table_data.append([data_str, desc, tipo, valor, saldo])

        if len(table_data) == 1:
            table_data.append(['', 'Nenhuma movimentacao no periodo', '',
                                '', ''])

        col_widths = [3*cm, 6.5*cm, 2.5*cm, 2.5*cm, 2.5*cm]
        trans_table = Table(table_data, colWidths=col_widths, repeatRows=1)
        trans_table.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1e3a5f')),
            ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 0), (-1, -1), 8),
            ('ALIGN', (3, 0), (-1, -1), 'RIGHT'),
            ('ROWBACKGROUNDS', (0, 1), (-1, -1),
             [colors.white, colors.HexColor('#f8fafc')]),
            ('BOX', (0, 0), (-1, -1), 0.5, colors.HexColor('#e2e8f0')),
            ('INNERGRID', (0, 0), (-1, -1), 0.3, colors.HexColor('#e2e8f0')),
            ('TOPPADDING', (0, 0), (-1, -1), 5),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 5),
            ('LEFTPADDING', (0, 0), (-1, -1), 6),
            ('RIGHTPADDING', (0, 0), (-1, -1), 6),
        ]))
        story.append(trans_table)

        doc.build(story)
        pdf_bytes = buffer.getvalue()

        filename = ('extrato_izylaudo_'
                    + datetime.now(TZ_BR).strftime('%Y%m%d_%H%M') + '.pdf')
        self.set_header('Content-Type', 'application/pdf')
        self.set_header('Content-Disposition',
                        'attachment; filename="' + filename + '"')
        self.finish(pdf_bytes)


